    'acp-op-splunk-audit-logs': {
        title: 'Audit Log Sync to Splunk – Application Control Plus',
        description: 'Forwards action log/audit data from Application Control Plus to Splunk for centralized SIEM analysis.',
        flowchartImage: '',
        content: `

            <h3>How This Works</h3>
            <div class="flowchart-container">
                <p class="flowchart-placeholder">Flowchart image will be added here.</p>
            </div>

            

            <h3>Prerequisites</h3>
            <ul>
                <li>Splunk instance with HTTP Event Collector (HEC) enabled.</li>
                <li>A valid HEC token configured in Splunk.</li>
                <li>Application Control Plus server must have outbound HTTPS access to the Splunk HEC URL.</li>
                <li>The integration must be enabled in Application Control Plus's admin settings.</li>
            </ul>

            <h3>Known Limitations</h3>
            <ul>
                <li>Only action log viewer data (audit logs) is synced — operational data like inventory or patch status requires separate configuration.</li>
                <li>If the Splunk HEC endpoint is unreachable, logs may be queued and sent once connectivity is restored (depends on retry configuration).</li>
                <li>Large environments with high audit log volume may require Splunk indexing capacity planning.</li>
            </ul>

            <h3>Logs for Troubleshooting</h3>
            <ul>
                <li><strong>Application Control Plus server:</strong> <code>&lt;Install_Dir&gt;/logs/splunkintegration.log</code></li>
                <li>Verify HEC token and URL in Application Control Plus → Admin → Integrations → Splunk.</li>
                <li>In Splunk, search <code>index=* sourcetype="application_control_plus"</code> to verify data receipt.</li>
            </ul>
            
        `,
        links: []
    },
