    'bsp-op-jira-iframe': {
        title: 'Load Browser Security Plus iFrame in Jira',
        description: 'Embed the Browser Security Plus console inside Jira for unified access without switching between consoles.',
        flowchartImage: '',
        content: `

            <h3>How This Works</h3>
            <div class="flowchart-container">
                <p class="flowchart-placeholder">Flowchart image will be added here.</p>
            </div>

            

            <h3>Prerequisites</h3>
            <ul>
                <li>Both Browser Security Plus and Jira servers must be reachable from the technician's browser.</li>
                <li>Integration must be configured with valid API credentials.</li>
                <li>If using HTTPS, both products must have valid SSL certificates. Mixed content (HTTP inside HTTPS) will be blocked by browsers.</li>
            </ul>

            <h3>Known Limitations</h3>
            <ul>
                <li>If the Browser Security Plus server has <code>X-Frame-Options</code> set to DENY or SAMEORIGIN, the iFrame will not load. This header may need to be adjusted.</li>
                <li>Browser security policies may block cross-origin iFrames if the domains differ significantly.</li>
                <li>Performance may be slightly slower than directly accessing the Browser Security Plus console, as the page is loaded within another page.</li>
                <li>Some browser extensions (ad blockers, privacy tools) may interfere with iFrame loading.</li>
            </ul>

            <h3>Logs for Troubleshooting</h3>
            <ul>
                <li>Check the <strong>browser developer console</strong> (F12 → Console tab) for Content Security Policy (CSP) or X-Frame-Options errors.</li>
                <li><strong>Browser Security Plus server:</strong> <code>&lt;Install_Dir&gt;/logs/serverout.txt</code> for access/authentication errors.</li>
                <li>Ensure both servers use the same protocol (both HTTP or both HTTPS).</li>
            </ul>
            
        `,
        links: []
    },
