    'ec-op-qradar-audit-logs-syslog': {
        title: 'Audit Log Sync to Syslog/SIEM – Endpoint Central',
        description: 'Forwards action log/audit data from Endpoint Central to a Syslog server or SIEM solution.',
        flowchartImage: '',
        content: `

            <h3>How This Works</h3>
            <div class="flowchart-container">
                <p class="flowchart-placeholder">Flowchart image will be added here.</p>
            </div>

            

            <h3>Prerequisites</h3>
            <ul>
                <li>A Syslog server or SIEM solution (e.g., EventLog Analyzer, Splunk, QRadar, ArcSight) that accepts syslog input.</li>
                <li>Network connectivity from Endpoint Central server to the Syslog server on the configured port.</li>
                <li>The integration must be enabled in Endpoint Central.</li>
            </ul>

            <h3>Known Limitations</h3>
            <ul>
                <li>UDP-based syslog does not guarantee delivery — use TCP/TLS for reliable transmission.</li>
                <li>Only audit log data is forwarded. Patch/vulnerability data requires separate integrations.</li>
                <li>Firewall rules must allow outbound traffic from Endpoint Central to the Syslog server.</li>
            </ul>

            <h3>Logs for Troubleshooting</h3>
            <ul>
                <li><strong>Endpoint Central server:</strong> <code>&lt;Install_Dir&gt;/logs/syslogintegration.log</code></li>
                <li>Verify syslog server IP, port, and protocol in Endpoint Central → Admin → Integrations.</li>
                <li>Test connectivity: <code>telnet &lt;syslog_server_ip&gt; &lt;port&gt;</code> from the Endpoint Central server.</li>
            </ul>
            
        `,
        links: []
    },
