    'mdm-op-syslog-cloud-audit-logs': {
        title: 'Audit Log Sync to Syslog/SIEM – Mobile Device Manager Plus',
        description: 'Forwards action log/audit data from Mobile Device Manager Plus to a Syslog server or SIEM solution.',
        flowchartImage: '',
        content: `

            <h3>How This Works</h3>
            <div class="flowchart-container">
                <p class="flowchart-placeholder">Flowchart image will be added here.</p>
            </div>

            

            <h3>Prerequisites</h3>
            <ul>
                <li>A Syslog server or SIEM solution (e.g., EventLog Analyzer, Splunk, QRadar, ArcSight) that accepts syslog input.</li>
                <li>Network connectivity from Mobile Device Manager Plus server to the Syslog server on the configured port.</li>
                <li>The integration must be enabled in Mobile Device Manager Plus.</li>
            </ul>

            <h3>Known Limitations</h3>
            <ul>
                <li>UDP-based syslog does not guarantee delivery — use TCP/TLS for reliable transmission.</li>
                <li>Only audit log data is forwarded. Patch/vulnerability data requires separate integrations.</li>
                <li>Firewall rules must allow outbound traffic from Mobile Device Manager Plus to the Syslog server.</li>
            </ul>

            <h3>Logs for Troubleshooting</h3>
            <ul>
                <li><strong>Mobile Device Manager Plus server:</strong> <code>&lt;Install_Dir&gt;/logs/syslogintegration.log</code></li>
                <li>Verify syslog server IP, port, and protocol in Mobile Device Manager Plus → Admin → Integrations.</li>
                <li>Test connectivity: <code>telnet &lt;syslog_server_ip&gt; &lt;port&gt;</code> from the Mobile Device Manager Plus server.</li>
            </ul>
            
        `,
        links: []
    },
