    'mdm-sdp-iframe': {
        title: 'Load Mobile Device Manager Plus iFrame in ServiceDesk Plus',
        description: 'Embed the Mobile Device Manager Plus console inside ServiceDesk Plus for unified access without switching between consoles.',
        flowchartImage: '',
        content: `

            <h3>How This Works</h3>
            <div class="flowchart-container">
                <p class="flowchart-placeholder">Flowchart image will be added here.</p>
            </div>

            

            <h3>Prerequisites</h3>
            <ul>
                <li>Both Mobile Device Manager Plus and ServiceDesk Plus servers must be reachable from the technician's browser.</li>
                <li>Integration must be configured with valid API credentials.</li>
                <li>If using HTTPS, both products must have valid SSL certificates. Mixed content (HTTP inside HTTPS) will be blocked by browsers.</li>
            </ul>

            <h3>Known Limitations</h3>
            <ul>
                <li>If the Mobile Device Manager Plus server has <code>X-Frame-Options</code> set to DENY or SAMEORIGIN, the iFrame will not load. This header may need to be adjusted.</li>
                <li>Browser security policies may block cross-origin iFrames if the domains differ significantly.</li>
                <li>Performance may be slightly slower than directly accessing the Mobile Device Manager Plus console, as the page is loaded within another page.</li>
                <li>Some browser extensions (ad blockers, privacy tools) may interfere with iFrame loading.</li>
            </ul>

            <h3>Logs for Troubleshooting</h3>
            <ul>
                <li>Check the <strong>browser developer console</strong> (F12 → Console tab) for Content Security Policy (CSP) or X-Frame-Options errors.</li>
                <li><strong>Mobile Device Manager Plus server:</strong> <code>&lt;Install_Dir&gt;/logs/serverout.txt</code> for access/authentication errors.</li>
                <li>Ensure both servers use the same protocol (both HTTP or both HTTPS).</li>
            </ul>
            
        `,
        links: []
    },
    'mdm-sdp-inventory-sync': {
        title: 'Inventory Asset Sync – Mobile Device Manager Plus → ServiceDesk Plus',
        description: 'Synchronizes hardware and software inventory data from Mobile Device Manager Plus to ServiceDesk Plus, keeping asset records up to date.',
        flowchartImage: '',
        content: `

            <h3>How This Works</h3>
            <div class="flowchart-container">
                <p class="flowchart-placeholder">Flowchart image will be added here.</p>
            </div>

            

            <h3>Prerequisites</h3>
            <ul>
                <li>Mobile Device Manager Plus and ServiceDesk Plus must be integrated (API key configured on both sides).</li>
                <li>Network connectivity between both servers on the configured ports.</li>
                <li>The API key must be associated with a technician having admin-level privileges.</li>
                <li>Deployment mode: <strong>Cloud to Cloud</strong>.</li>
            </ul>

            <h3>Known Limitations</h3>
            <ul>
                <li>If "Stop uploading scanned XMLs via non-login URL" is enabled in the target's advanced security settings, asset sync will fail.</li>
                <li>Network/firewall issues between servers will block synchronization.</li>
                <li>Both products should use the same protocol (HTTP or HTTPS) for successful communication.</li>
                <li>Sync is one-directional — data flows only from Mobile Device Manager Plus to ServiceDesk Plus.</li>
            </ul>

            <h3>Logs for Troubleshooting</h3>
            <ul>
                <li><strong>Mobile Device Manager Plus side:</strong> <code>&lt;Mobile Device Manager Plus_Home&gt;/logs/sdpintegration.txt</code></li>
                <li><strong>ServiceDesk Plus side:</strong> Check the integration module logs under the ServiceDesk Plus logs directory.</li>
                <li>Look for HTTP error codes (401 = authentication failure, 403 = permission issue, 500 = server error).</li>
                <li>Verify the API key is active and not expired.</li>
            </ul>
            
        `,
        links: []
    },
